const remoteJid = $('Webhook').first().json.body.data.key.remoteJid;
const rows = $input.all().map(i => i.json).filter(i => i.telefono === remoteJid);
if (rows.length === 0) {
  return []; // Ya fue procesado por otra ejecución
}
// Buscar el timestamp más reciente
let maxTimestamp = 0;
rows.forEach(r => {
  if (r.timestamp > maxTimestamp) maxTimestamp = r.timestamp;
});
const now = Date.now();
// Si la diferencia es menor a 59 segundos, significa que entró OTRO mensaje después de nosotros, por lo que nosotros morimos y dejamos que el OTRO proceso responda.
let isManual = false;
try { isManual = ($execution.mode === 'manual'); } catch(e) {}
if (!isManual && (now - maxTimestamp < 14000)) {
  return []; 
}
// ¡Somos el último proceso! Unimos todos los mensajes
const combined = rows.sort((a,b) => a.timestamp - b.timestamp).map(r => r.mensaje).join('\n');
return [{ json: { combined_message: combined, telefono: remoteJid } }];

const original = $input.first().json;
let texto = original.output.mensaje_whatsapp || '';
let partes = texto.split('|||').map(t => t.trim()).filter(t => t.length > 0);
if (partes.length === 0) partes = [texto]; // Fallback
return partes.map(p => { 
  let newJson = JSON.parse(JSON.stringify(original));
  newJson.output.mensaje_whatsapp_chunk = p;
  return { json: newJson };
});

const remoteJid = $('Webhook').first().json.body.data.key.remoteJid;
const mensaje = $('Webhook').first().json.body.data.message.conversation;
return [{ json: {
  telefono: remoteJid,
  mensaje: mensaje,
  timestamp: Date.now()
} }];
